const row = $input.first().json;
const failures = parseInt(row.failure_count) || 0;
const total = parseInt(row.total_count) || 0;
const lastSeen = row.last_seen;

// Pipeline dead — no results at all in last 30 minutes
if (total === 0) {
  return [{ json: { alertType: 'dead', message: '💀 **Monitor pipeline is down**\n\nNo results received in the last 30 minutes.\nGitHub Actions may have stopped running.\n\nCheck: https://github.com/DeveloperAlly/gamerslab/actions' } }];
}

// Region failures
if (failures > 0) {
  return [{ json: { alertType: 'failure', message: `🚨 **Geo monitor failures detected**\n\n**Failed checks:** ${failures} of ${total} in last 30 min\n**Last result:** ${lastSeen}` } }];
}

// All good — no alert
return [];
